/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_application_status_change` AFTER UPDATE ON `applications` FOR EACH ROW BEGIN
    IF OLD.status != NEW.status THEN
        INSERT INTO notifications (user_id, message)
        SELECT c.user_id, 
               CONCAT('Status changed from ', OLD.status, ' to ', NEW.status, ' for application #', NEW.application_id)
        FROM candidates c
        WHERE c.candidate_id = NEW.candidate_id;
    END IF;
END */;;
