/*!50001 CREATE ALGORITHM=UNDEFINED */
/*!50013 DEFINER=`root`@`localhost` SQL SECURITY DEFINER */
/*!50001 VIEW `v_candidate_dashboard` AS select `u`.`user_id` AS `user_id`,`u`.`full_name` AS `full_name`,`u`.`email` AS `email`,`c`.`skills` AS `skills`,`c`.`experience_years` AS `experience_years`,`c`.`education` AS `education`,count(`a`.`application_id`) AS `total_applications`,sum((case when (`a`.`status` = 'shortlisted') then 1 else 0 end)) AS `shortlisted`,sum((case when (`a`.`status` = 'interview_scheduled') then 1 else 0 end)) AS `interviews` from ((`users` `u` join `candidates` `c` on((`u`.`user_id` = `c`.`user_id`))) left join `applications` `a` on((`c`.`candidate_id` = `a`.`candidate_id`))) where (`u`.`role` = 'candidate') group by `u`.`user_id`,`u`.`full_name`,`u`.`email`,`c`.`skills`,`c`.`experience_years`,`c`.`education` */;
/*!50001 SET character_set_client      = @saved_cs_client */;
/*!50001 SET character_set_results     = @saved_cs_results */;
/*!50001 SET collation_connection      = @saved_col_connection */;

