/*!50001 CREATE ALGORITHM=UNDEFINED */
/*!50013 DEFINER=`root`@`localhost` SQL SECURITY DEFINER */
/*!50001 VIEW `v_job_deadlines` AS select `jobs`.`job_id` AS `job_id`,`jobs`.`title` AS `title`,`jobs`.`deadline` AS `deadline`,date_format(`jobs`.`deadline`,'%M %d, %Y') AS `formatted_deadline`,(to_days(`jobs`.`deadline`) - to_days(curdate())) AS `days_remaining`,concat(`jobs`.`title`,' - ',convert(date_format(`jobs`.`deadline`,'%b %d') using utf8mb4)) AS `job_summary` from `jobs` where (`jobs`.`status` = 'open') */;
